@startuml
!theme plain
skinparam backgroundColor #FFFFFF
skinparam rectangle {
  BackgroundColor #F5F5F5
  BorderColor #000000
  BorderThickness 1
  FontColor #000000
}
skinparam note {
  BackgroundColor #B0E0E6
  BorderColor #000000
  BorderThickness 1
  FontColor #000000
}

rectangle "HTM" {
  note right of "HTM"
    <b>HTML</b>
  end note
}

@enduml
